var total = $('Prepare Data').first().json.images.length;
if(total > 1){
  var binary = '';
  for(var i = 0; i<total;i++){
    binary += i == 0 ? 'image' : ',image_'+i;
  }
  return {
    binary:binary,
    images: $('Prepare Data').first().json.images
  };
}else{
  return {binary:'image',images: $('Prepare Data').first().json.images };
}

function removeBase64Header(base64String) {
  if (typeof base64String !== "string") return base64String;
  const commaIndex = base64String.indexOf(",");
  return commaIndex !== -1 ? base64String.slice(commaIndex + 1) : base64String;
}
return {image: removeBase64Header($input.first().json.image) }
